# Load stocks and targets if provided
stocks = {}
targets = {}
if args.stocks:
    stocks = planner.load_stock_file(args.stocks)
if args.targets:
    targets = planner.load_stock_file(args.targets)

# Get config values
te_bonus = config.get('te_bonus', 0)
invention_skill = config.get('invention_skill', 5)
comp_defaults = config.get('component_bpo_defaults', {})
comp_me = comp_defaults.get('me', 10)
comp_te = comp_defaults.get('te', 20)

# Generate plan
try:
    if args.build_all:
        plan = planner.generate_build_all_plan(args.build_string, config)
    else:
        plan = planner.generate_plan(args.build_string, config)
except ValueError as e:
    print(f'Error: {e}', file=sys.stderr)
    sys.exit(1)

# Calculate stock targets if targets file is provided
if targets:
    stock_plan = planner.calculate_stock_targets(
        stocks, targets, comp_me, comp_te, invention_skill, te_bonus
    )

    # Merge stock jobs into plan
    for job_name, runs in stock_plan['to_build'].items():
        # Check if job already exists
        found = False
        for job in plan['jobs']:
            if job['name'] == job_name:
                job['runs'] += runs
                job['count'] += 1
                found = True
                break
        if not found:
            plan['jobs'].append({
                'name': job_name,
                'runs': runs,
                'days': 0.0,  # Will be calculated below
                'count': 1
            })

    # Merge stock materials into plan
    for mat_name, qty in stock_plan['to_buy'].items():
        found = False
        for mat in plan['materials']:
            if mat['name'] == mat_name:
                mat['to_buy'] += qty
                mat['buy_volume'] = math.ceil(mat['to_buy'] / 100) * 100
                found = True
                break
        if not found:
            plan['materials'].append({
                'name': mat_name,
                'to_buy': qty,
                'buy_volume': math.ceil(qty / 100) * 100,
                'start_amount': 0,
                'end_amount': 0
            })

    # Merge invention/manufacture materials
    for mat_name, qty in stock_plan['materials'].items():
        found = False
        for mat in plan['materials']:
            if mat['name'] == mat_name:
                mat['to_buy'] += qty
                mat['buy_volume'] = math.ceil(mat['to_buy'] / 100) * 100
                found = True
                break
        if not found:
            plan['materials'].append({
                'name': mat_name,
                'to_buy': qty,
                'buy_volume': math.ceil(qty / 100) * 100,
                'start_amount': 0,
                'end_amount': 0
            })

# Update materials.csv with start_amount and end_amount from stocks
for mat in plan['materials']:
    if mat['name'] in stocks:
        mat['start_amount'] = stocks[mat['name']]
        # Calculate end_amount: start - consumed + produced
        # For items we need to buy, they're consumed
        consumed = mat['to_buy']
        end_amount = stocks[mat['name']] - consumed
        mat['end_amount'] = max(0, end_amount)
    else:
        mat['start_amount'] = 0
        mat['end_amount'] = 0

# Sort jobs and materials
plan['jobs'].sort(key=lambda x: x['name'].lower())
plan['materials'].sort(key=lambda x: x['name'].lower())

# Write CSV files
planner.write_plan_csvs(plan, args.output)

print(f'Plan generated successfully in {args.output}')
print(f'  Materials: {args.output}/materials.csv')
print(f'  Jobs: {args.output}/jobs.csv')

