        if not product:
            # Not found, need to buy
            if target_name not in material_flows:
                material_flows[target_name] = {
                    'name': target_name,
                    'start_amount': current_qty,
                    'consumed': deficit,
                    'produced': 0
                }
            else:
                material_flows[target_name]['consumed'] += deficit
            continue

        # Check if buildable
        bp = planner.find_bp_for_product(product['typeID'])
        is_reaction = False

        if not bp:
            # Check if it's produced via reactions
            for (type_id, activity_id) in planner.industry_activities:
                if activity_id == planner.ACTIVITY_REACTIONS:
                    if type_id == product['typeID']:
                        is_reaction = True
                        activity_key = (type_id, activity_id)
                        break

        if bp or is_reaction:
            # Buildable - calculate runs needed
            if bp:
                activity_key = (bp['typeID'], planner.ACTIVITY_MANUFACTURING)
                output_per_run = 1
                if activity_key in planner.industry_products:
                    products_list = planner.industry_products[activity_key]
                    for p in products_list:
                        output_per_run = p['quantity']
                        break
            else:
                activity_key = (product['typeID'], planner.ACTIVITY_REACTIONS)
                output_per_run = 1
                if activity_key in planner.industry_products:
                    products_list = planner.industry_products[activity_key]
                    for p in products_list:
                        output_per_run = p['quantity']
                        break

            runs_needed = (deficit + output_per_run - 1) // output_per_run
            total_produced = runs_needed * output_per_run

            # Get materials for this job
            if bp:
                materials_list = planner.industry_materials.get(activity_key, [])
                for mat in materials_list:
                    mat_type_id = mat['materialTypeID']
                    mat_name = planner.get_item_name(mat_type_id) or f'Unknown ({mat_type_id})'
                    original_qty = mat['quantity']
                    adjusted_qty = math.ceil(max(1, original_qty * (1 - comp_me / 100)))
                    total_mat_qty = adjusted_qty * runs_needed

                    if mat_name not in material_flows:
                        # Start from current stock if available
                        start_from_stock = stocks.get(mat_name, 0)
                        material_flows[mat_name] = {
                            'name': mat_name,
                            'start_amount': start_from_stock,
                            'consumed': 0,
                            'produced': 0
                        }
                    material_flows[mat_name]['consumed'] += total_mat_qty
            else:
                # Reaction - get materials
                materials_list = planner.industry_materials.get(activity_key, [])
                for mat in materials_list:
                    mat_type_id = mat['materialTypeID']
                    mat_name = planner.get_item_name(mat_type_id) or f'Unknown ({mat_type_id})'
                    mat_qty = mat['quantity'] * runs_needed

                    if mat_name not in material_flows:
                        start_from_stock = stocks.get(mat_name, 0)
                        material_flows[mat_name] = {
                            'name': mat_name,
                            'start_amount': start_from_stock,
                            'consumed': 0,
                            'produced': 0
                        }
                    material_flows[mat_name]['consumed'] += mat_qty

            # Track production
            job_name = bp['typeName'] if bp else product['typeName']
            if not bp:  # Reaction
                job_name = job_name + ' Reaction Formula'

            if job_name not in material_flows:
                start_from_stock = stocks.get(job_name.replace(' Blueprint', '').replace(' Reaction Formula', ''), 0)
                material_flows[job_name] = {
                    'name': job_name,
                    'start_amount': start_from_stock,
                    'consumed': 0,
                    'produced': total_produced
                }
            else:
                material_flows[job_name]['produced'] += total_produced

